input.command:
kubectl exec -n mongodb mongo-rs-2 -- mongosh --tls --tlsCAFile /etc/mongo-ca/ca.crt --tlsAllowInvalidCertificates --host mongo-rs-2.mongo.mongodb.svc.cluster.local --eval '
var cfg = rs.conf();
cfg.members[0].horizons = { external: "domain-rs-1:31181" };
cfg.members[1].horizons = { external: "domain-rs-2:31182" };
cfg.members[2].horizons = { external: "domain-rs-3:31183" };
rs.reconfig(cfg);
' 2>&1 | tail -15
